import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../../contexts/AuthContext';
import './CustomerPages.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const CustomerRatings = () => {
  const [ratings, setRatings] = useState([]);
  const [transactions, setTransactions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showRatingForm, setShowRatingForm] = useState(false);
  const [selectedTransaction, setSelectedTransaction] = useState(null);
  const [rating, setRating] = useState(0);
  const [hover, setHover] = useState(0);
  const [comment, setComment] = useState('');
  const [submitting, setSubmitting] = useState(false);
  
  const { user } = useAuth();

  useEffect(() => {
    if (user) {
      fetchRatings();
      fetchUnratedTransactions();
    }
  }, [user]);

  const fetchRatings = async () => {
    try {
      const response = await axios.get(`${API_URL}/ratings/my-ratings`);
      setRatings(response.data.data || []);
    } catch (error) {
      console.error('Error fetching ratings:', error);
      setError('Failed to load ratings');
    }
  };

  const fetchUnratedTransactions = async () => {
    try {
      const response = await axios.get(`${API_URL}/transactions`);
      const allTransactions = response.data.data || [];
      
      // Get already rated transaction IDs
      const ratedTransactionIds = ratings.map(r => r.transactionId);
      
      // Filter out transactions that are already rated
      const unrated = allTransactions.filter(
        t => !ratedTransactionIds.includes(t.transactionId)
      );
      
      setTransactions(unrated);
    } catch (error) {
      console.error('Error fetching transactions:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleRatingSubmit = async (e) => {
    e.preventDefault();
    if (!selectedTransaction) return;
    
    setSubmitting(true);
    try {
      await axios.post(`${API_URL}/ratings`, {
        transactionId: selectedTransaction.transactionId,
        rating,
        comment
      });
      
      // Reset form
      setShowRatingForm(false);
      setSelectedTransaction(null);
      setRating(0);
      setComment('');
      
      // Refresh data
      await fetchRatings();
      await fetchUnratedTransactions();
      
    } catch (error) {
      console.error('Error submitting rating:', error);
      setError('Failed to submit rating');
    } finally {
      setSubmitting(false);
    }
  };

  const getStarDisplay = (rating) => {
    return '★'.repeat(rating) + '☆'.repeat(5 - rating);
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric'
    });
  };

  if (!user) {
    return (
      <div className="customer-dashboard">
        <div className="empty-state">
          <div className="empty-icon">⭐</div>
          <h3>Please Log In</h3>
          <p>You need to be logged in to view your ratings.</p>
          <Link to="/login" className="btn-primary">Go to Login</Link>
        </div>
      </div>
    );
  }

  return (
    <div className="customer-dashboard">
      <div className="page-header">
        <div>
          <h1 className="page-title">My Ratings</h1>
          <p className="page-description">Rate your purchases and manage your reviews</p>
        </div>
        {transactions.length > 0 && !showRatingForm && (
          <button 
            className="btn-primary"
            onClick={() => setShowRatingForm(true)}
          >
            + Rate a Purchase
          </button>
        )}
      </div>

      {error && (
        <div className="auth-error" style={{ marginBottom: '1.5rem' }}>
          {error}
        </div>
      )}

      {/* Rating Form Modal */}
      {showRatingForm && (
        <div className="modal-overlay" onClick={() => setShowRatingForm(false)}>
          <div className="modal-container" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2>Rate Your Purchase</h2>
              <button className="modal-close" onClick={() => setShowRatingForm(false)}>×</button>
            </div>
            
            <div className="modal-body">
              {/* Transaction Selector */}
              <div className="form-group">
                <label className="form-label">Select Transaction</label>
                <select 
                  className="form-select"
                  value={selectedTransaction?.transactionId || ''}
                  onChange={(e) => {
                    const trans = transactions.find(t => t.transactionId === e.target.value);
                    setSelectedTransaction(trans);
                  }}
                >
                  <option value="">Choose a transaction to rate</option>
                  {transactions.map((t) => (
                    <option key={t._id} value={t.transactionId}>
                      {t.riceType} - {t.quantityKg}kg (₱{t.amountPaid}) - {formatDate(t.createdAt)}
                    </option>
                  ))}
                </select>
              </div>

              {selectedTransaction && (
                <form onSubmit={handleRatingSubmit}>
                  {/* Star Rating */}
                  <div className="rating-stars-container">
                    <label className="rating-label">Your Rating</label>
                    <div className="stars">
                      {[1, 2, 3, 4, 5].map((star) => (
                        <button
                          key={star}
                          type="button"
                          onClick={() => setRating(star)}
                          onMouseEnter={() => setHover(star)}
                          onMouseLeave={() => setHover(0)}
                          className={`star-btn ${(hover || rating) >= star ? 'active' : ''}`}
                        >
                          ★
                        </button>
                      ))}
                    </div>
                    <div className="rating-text">
                      {rating === 1 && 'Poor'}
                      {rating === 2 && 'Fair'}
                      {rating === 3 && 'Good'}
                      {rating === 4 && 'Very Good'}
                      {rating === 5 && 'Excellent'}
                    </div>
                  </div>

                  {/* Comment */}
                  <div className="form-group">
                    <label className="form-label">Review (Optional)</label>
                    <textarea
                      value={comment}
                      onChange={(e) => setComment(e.target.value)}
                      rows="4"
                      className="form-textarea"
                      placeholder="Tell us about your experience with this product..."
                    />
                  </div>

                  {/* Action Buttons */}
                  <div className="form-actions">
                    <button
                      type="button"
                      onClick={() => {
                        setShowRatingForm(false);
                        setSelectedTransaction(null);
                        setRating(0);
                        setComment('');
                      }}
                      className="btn-secondary"
                    >
                      Cancel
                    </button>
                    <button
                      type="submit"
                      disabled={rating === 0 || submitting}
                      className="btn-primary"
                    >
                      {submitting ? 'Submitting...' : 'Submit Rating'}
                    </button>
                  </div>
                </form>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Ratings List */}
      {loading ? (
        <div className="loading-state">Loading ratings...</div>
      ) : ratings.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">⭐</div>
          <h3>No Ratings Yet</h3>
          <p>You haven't rated any purchases yet.</p>
          {transactions.length > 0 ? (
            <button 
              onClick={() => setShowRatingForm(true)} 
              className="btn-primary"
            >
              Rate Your First Purchase
            </button>
          ) : (
            <Link to="/customer/transactions" className="btn-primary">
              View Transactions
            </Link>
          )}
        </div>
      ) : (
        <>
          {/* Unrated Transactions Alert */}
          {transactions.length > 0 && (
            <div className="alert-card" style={{ marginBottom: '2rem' }}>
              <div className="alert-content">
                <span className="alert-icon">📝</span>
                <div className="alert-text">
                  <strong>{transactions.length}</strong> unrated purchase{transactions.length > 1 ? 's' : ''} waiting for your review!
                </div>
                <button 
                  className="btn-primary btn-small"
                  onClick={() => setShowRatingForm(true)}
                >
                  Rate Now
                </button>
              </div>
            </div>
          )}

          {/* Ratings Grid */}
          <div className="ratings-grid">
            {ratings.map((rating) => (
              <div key={rating._id} className="rating-card">
                <div className="rating-header">
                  <div className="rating-stars">
                    <span className="stars-display">{getStarDisplay(rating.rating)}</span>
                    <span className="rating-value">{rating.rating}/5</span>
                  </div>
                  <span className="rating-date">{formatDate(rating.createdAt)}</span>
                </div>
                
                <div className="rating-transaction">
                  Transaction: {rating.transactionId}
                </div>
                
                {rating.comment && (
                  <div className="rating-comment">
                    <p>{rating.comment}</p>
                  </div>
                )}

                {rating.adminReply && (
                  <div className="admin-reply">
                    <div className="reply-header">
                      <span className="reply-label">Store Response</span>
                      <span className="reply-date">{formatDate(rating.repliedAt)}</span>
                    </div>
                    <p className="reply-content">{rating.adminReply}</p>
                  </div>
                )}
              </div>
            ))}
          </div>
        </>
      )}
    </div>
  );
};

export default CustomerRatings;
